const d = msg.payload;
const tempMin = parseInt(env.get('TEMP_MIN') || 15);
const tempMax = parseInt(env.get('TEMP_MAX') || 22);
const meta    = parseFloat(env.get('VOLUME_META_LITROS') || 50);

if (isNaN(d.temperature_c) || isNaN(d.humidity_pct)) {
    node.warn('Leitura invalida descartada');
    node.send([null, { payload: {
        timestamp: new Date(),
        level: 'WARN',
        service: 'node-red',
        message: 'Leitura invalida descartada (NaN)',
        device_id: d.device_id || 'unknown'
    }}]);
    return null;
}

const rendimento = parseFloat(((d.volume_liters / meta) * 100).toFixed(2));
const lossPct    = parseFloat((100 - rendimento).toFixed(2));
const stock      = parseFloat((d.volume_liters * 0.92).toFixed(2));

msg.payload = {
    ...d,
    collected_at:   new Date(),
    temp_status:    (d.temperature_c >= tempMin && d.temperature_c <= tempMax) ? 'OK' : 'ALERTA',
    rendimento_pct: rendimento,
    loss_pct:       lossPct,
    stock_liters:   stock
};

return [msg, null];

msg.payload = {
    timestamp: new Date(),
    level: 'ERROR',
    service: 'node-red',
    message: msg.error.message,
    stack: msg.error.source
};
return msg;

msg.payload = {
    collected_at: new Date(),
    type: 'service',
    name: 'node-red',
    status: msg.statusCode === 200 ? 'up' : 'down',
    latency_ms: msg.responseTime || 0
};
return msg;

msg.payload = {
    collected_at: new Date(),
    type: 'service',
    name: 'grafana',
    status: msg.statusCode === 200 ? 'up' : 'down',
    latency_ms: msg.responseTime || 0
};
return msg;

const lastSeen = global.get('esp32_last_seen') || 0;
const secAgo   = Math.floor((Date.now() - lastSeen) / 1000);
const timeout  = parseInt(env.get('SENSOR_TIMEOUT_SECONDS') || 120);

msg.payload = {
    collected_at: new Date(),
    type: 'sensor',
    name: 'esp32-brewery-01',
    status: secAgo < timeout ? 'up' : 'down',
    seconds_since_last_ping: secAgo
};
return msg;
